// SPDX-License-Identifier: LGPL-3.0-only
//! DCF-Audio: collaborative audio over the DeModFrame wire.
//!
//! Audio is an *adapter* over the 17-byte DeModFrame quantum (`frame.rs`), not a new
//! wire format. A 20 ms codec block is serialised into `1 + frag_total` ordinary CTRL
//! frames. This L2 framing is codec-agnostic and byte-deterministic across C/Rust/Python
//! — it is pinned by `Documentation/audio_vectors.json`. See `Documentation/DCF_AUDIO_SPEC.md`.
//!
//! Layout (all frames version=1, type=CTRL(3), big-endian):
//!   seq = packet_id[15:5] (11 bits) | frag_idx[4:0] (5 bits)
//!   frag_idx 0  descriptor : payload = [payload_len, frag_total, codec_id, flags]
//!   frag_idx k  data       : payload = bytes[(k-1)*4 .. +4]  (last frame zero-padded)
//!   frag_total = ceil(payload_len/4)  (<= 31  =>  payload_len <= 124 bytes / 20 ms)

use crate::{Frame, FrameType};
use std::collections::BTreeMap;

// ── L2 constants ────────────────────────────────────────────────────────────
pub const FRAG_BITS: u16 = 5;
pub const FRAG_MASK: u16 = 0x1F;
pub const MAX_FRAGS: usize = 31;
pub const MAX_PAYLOAD: usize = MAX_FRAGS * 4; // 124 bytes / 20 ms block
pub const MAX_PACKET_ID: u16 = (1 << (16 - FRAG_BITS)) - 1; // 2047

// Codec ids (profiles in DCF_AUDIO_SPEC.md).
pub const CODEC_OPUS: u8 = 0;
pub const CODEC_PCM_DIAG: u8 = 1;
pub const CODEC_FAUST_PM: u8 = 2;
// id 3 reserved (declined low-bitrate speech codec)

// Descriptor flag bits.
pub const FLAG_END_TALKSPURT: u8 = 0x01;
pub const FLAG_PM_VOICE: u8 = 0x02;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AudioError {
    /// Codec block exceeds the 124-byte / 20 ms cap.
    PayloadTooLarge,
    /// packet_id exceeds the 11-bit field.
    BadPacketId,
}

// ── L2: packetize ───────────────────────────────────────────────────────────
/// Serialise one codec block into DeModFrame CTRL frames (descriptor first, then
/// data fragments in order). Each frame is a fully valid 17-byte DeModFrame.
pub fn packetize(
    codec_id: u8,
    payload: &[u8],
    packet_id: u16,
    ts_us: u32,
    src: u16,
    dst: u16,
    flags: u8,
) -> Result<Vec<[u8; 17]>, AudioError> {
    if payload.len() > MAX_PAYLOAD {
        return Err(AudioError::PayloadTooLarge);
    }
    if packet_id > MAX_PACKET_ID {
        return Err(AudioError::BadPacketId);
    }
    let frag_total = ((payload.len() + 3) / 4) as u8;
    let mut frames = Vec::with_capacity(1 + frag_total as usize);

    // frag_idx 0 — descriptor
    let desc_seq = packet_id << FRAG_BITS;
    let desc = [payload.len() as u8, frag_total, codec_id, flags];
    frames.push(Frame::new(1, FrameType::Ctrl, desc_seq, src, dst, desc, ts_us).encode());

    // frag_idx 1..frag_total — data, last chunk zero-padded
    for k in 1..=frag_total {
        let off = (k as usize - 1) * 4;
        let mut chunk = [0u8; 4];
        let end = (off + 4).min(payload.len());
        chunk[..end - off].copy_from_slice(&payload[off..end]);
        let seq = (packet_id << FRAG_BITS) | k as u16;
        frames.push(Frame::new(1, FrameType::Ctrl, seq, src, dst, chunk, ts_us).encode());
    }
    Ok(frames)
}

// ── L2: reassembler ─────────────────────────────────────────────────────────
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AudioPacket {
    pub packet_id: u16,
    pub ts_us: u32,
    pub codec_id: u8,
    pub flags: u8,
    pub payload: Vec<u8>,
}

#[derive(Default)]
struct Slot {
    desc: Option<(u8, u8, u8, u8)>, // (payload_len, frag_total, codec_id, flags)
    ts_us: u32,
    frags: BTreeMap<u8, [u8; 4]>,
}

/// Stateful reassembler. `push` emits a completed packet as soon as its descriptor
/// and every data fragment have arrived; duplicates are ignored; `finalize` reports
/// any still-incomplete packet as lost. Mirrors the C and Python references.
#[derive(Default)]
pub struct AudioReassembler {
    slots: BTreeMap<u16, Slot>,
}

impl AudioReassembler {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&mut self, frame: &[u8; 17]) -> Option<AudioPacket> {
        let d = Frame::decode(&frame[..]).ok()?;
        if d.frame_type != FrameType::Ctrl {
            return None;
        }
        let packet_id = d.seq >> FRAG_BITS;
        let frag_idx = (d.seq & FRAG_MASK) as u8;
        let entry = self.slots.entry(packet_id).or_default();
        entry.ts_us = d.timestamp_us;
        if frag_idx == 0 {
            if entry.desc.is_none() {
                entry.desc = Some((d.payload[0], d.payload[1], d.payload[2], d.payload[3]));
            }
        } else {
            entry.frags.entry(frag_idx).or_insert(d.payload);
        }
        self.try_emit(packet_id)
    }

    fn try_emit(&mut self, packet_id: u16) -> Option<AudioPacket> {
        let entry = self.slots.get(&packet_id)?;
        let (payload_len, frag_total, codec_id, flags) = entry.desc?;
        if (1..=frag_total).any(|k| !entry.frags.contains_key(&k)) {
            return None;
        }
        let mut raw = Vec::with_capacity(frag_total as usize * 4);
        for k in 1..=frag_total {
            raw.extend_from_slice(&entry.frags[&k]);
        }
        raw.truncate(payload_len as usize);
        let ts_us = entry.ts_us;
        self.slots.remove(&packet_id);
        Some(AudioPacket { packet_id, ts_us, codec_id, flags, payload: raw })
    }

    /// Report every still-incomplete packet as lost (ascending packet_id), clearing state.
    pub fn finalize(&mut self) -> Vec<u16> {
        let lost: Vec<u16> = self.slots.keys().copied().collect(); // BTreeMap => sorted
        self.slots.clear();
        lost
    }
}

// ── L1: codec interface + registry ──────────────────────────────────────────
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct CodecProfile {
    pub codec_id: u8,
    pub sample_rate: u32,
    pub channels: u8,
    pub block_samples: u16,
    pub max_payload: u16,
}

/// One pluggable codec keyed by `codec_id`. Output is opaque to the L2 framing.
pub trait AudioCodec {
    fn profile(&self) -> CodecProfile;
    fn encode(&mut self, pcm: &[f32]) -> Vec<u8>;
    fn decode(&mut self, data: &[u8]) -> Vec<f32>;
    /// Packet-loss concealment: synthesise one block with no input.
    fn plc(&mut self) -> Vec<f32>;
}

/// Return a codec instance for `codec_id`, or `None` if not built in this config.
pub fn codec_for(codec_id: u8) -> Option<Box<dyn AudioCodec>> {
    match codec_id {
        CODEC_PCM_DIAG => Some(Box::new(PcmDiag)),
        #[cfg(feature = "opus")]
        CODEC_OPUS => opus_codec::OpusCodec::new().map(|c| Box::new(c) as Box<dyn AudioCodec>),
        #[cfg(feature = "pm")]
        CODEC_FAUST_PM => Some(Box::new(pm::FaustPmCodec::new())),
        _ => None,
    }
}

// ── L1: PCM-diagnostic codec (id 1) — 6 kHz 8-bit mono, 120 B/block ─────────
pub const PCM_DIAG_RATE: u32 = 6000;
pub const PCM_DIAG_BLOCK: usize = 120;

/// float [-1,1] -> unsigned 8-bit (mid 128). decode∘encode is byte-lossless.
pub fn pcm_diag_encode(samples: &[f32]) -> Vec<u8> {
    samples
        .iter()
        .map(|&s| ((s * 128.0).round() as i32 + 128).clamp(0, 255) as u8)
        .collect()
}
/// unsigned 8-bit -> float [-1,1].
pub fn pcm_diag_decode(data: &[u8]) -> Vec<f32> {
    data.iter().map(|&b| (b as f32 - 128.0) / 128.0).collect()
}

pub struct PcmDiag;
impl AudioCodec for PcmDiag {
    fn profile(&self) -> CodecProfile {
        CodecProfile {
            codec_id: CODEC_PCM_DIAG,
            sample_rate: PCM_DIAG_RATE,
            channels: 1,
            block_samples: PCM_DIAG_BLOCK as u16,
            max_payload: PCM_DIAG_BLOCK as u16,
        }
    }
    fn encode(&mut self, pcm: &[f32]) -> Vec<u8> {
        pcm_diag_encode(pcm)
    }
    fn decode(&mut self, data: &[u8]) -> Vec<f32> {
        pcm_diag_decode(data)
    }
    fn plc(&mut self) -> Vec<f32> {
        vec![0.0; PCM_DIAG_BLOCK]
    }
}

// ── L1: PM (Faust phase-mod, id 2) — 8-byte parameter layout (certified) ────
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct PmParams {
    pub f0: u16,
    pub amp: u8,
    pub mod_index: u8,
    pub mod_ratio: u8,
    pub bright: u8,
    pub env: u8,
    pub flags: u8,
}

pub fn pm_pack(p: &PmParams) -> [u8; 8] {
    [
        (p.f0 >> 8) as u8,
        p.f0 as u8,
        p.amp,
        p.mod_index,
        p.mod_ratio,
        p.bright,
        p.env,
        p.flags,
    ]
}
pub fn pm_unpack(b: &[u8; 8]) -> PmParams {
    PmParams {
        f0: ((b[0] as u16) << 8) | b[1] as u16,
        amp: b[2],
        mod_index: b[3],
        mod_ratio: b[4],
        bright: b[5],
        env: b[6],
        flags: b[7],
    }
}

// ── L1: Opus codec (id 0) — feature "opus" ──────────────────────────────────
#[cfg(feature = "opus")]
mod opus_codec {
    use super::*;
    use opus::{Application, Channels, Decoder, Encoder};

    pub const OPUS_RATE: u32 = 48000;
    pub const OPUS_BLOCK: usize = 960; // 20 ms @ 48 kHz

    pub struct OpusCodec {
        enc: Encoder,
        dec: Decoder,
    }
    impl OpusCodec {
        pub fn new() -> Option<Self> {
            let mut enc = Encoder::new(OPUS_RATE, Channels::Mono, Application::Audio).ok()?;
            let _ = enc.set_bitrate(opus::Bitrate::Bits(24000));
            let dec = Decoder::new(OPUS_RATE, Channels::Mono).ok()?;
            Some(Self { enc, dec })
        }
    }
    impl AudioCodec for OpusCodec {
        fn profile(&self) -> CodecProfile {
            CodecProfile {
                codec_id: CODEC_OPUS,
                sample_rate: OPUS_RATE,
                channels: 1,
                block_samples: OPUS_BLOCK as u16,
                max_payload: MAX_PAYLOAD as u16,
            }
        }
        fn encode(&mut self, pcm: &[f32]) -> Vec<u8> {
            let mut out = vec![0u8; MAX_PAYLOAD];
            match self.enc.encode_float(pcm, &mut out) {
                Ok(n) => {
                    out.truncate(n);
                    out
                }
                Err(_) => Vec::new(),
            }
        }
        fn decode(&mut self, data: &[u8]) -> Vec<f32> {
            let mut pcm = vec![0.0f32; OPUS_BLOCK];
            match self.dec.decode_float(data, &mut pcm, false) {
                Ok(n) => {
                    pcm.truncate(n);
                    pcm
                }
                Err(_) => vec![0.0; OPUS_BLOCK],
            }
        }
        fn plc(&mut self) -> Vec<f32> {
            // An empty input slice tells libopus to conceal one lost packet.
            let mut pcm = vec![0.0f32; OPUS_BLOCK];
            let _ = self.dec.decode_float(&[], &mut pcm, false);
            pcm
        }
    }
}

// ── L1: Faust phase-mod synthesis (id 2) — feature "pm" ─────────────────────
#[cfg(feature = "pm")]
mod pm {
    use super::*;

    pub const PM_RATE: u32 = 48000;
    pub const PM_BLOCK: usize = 960;

    extern "C" {
        // Provided by codec/faust/dcf_pm_codec.gen.c (compiled by build.rs).
        // Synthesises `n` samples from the 8-byte param block.
        fn dcf_pm_synth_block_ffi(params8: *const u8, out: *mut f32, n: i32);
    }

    pub struct FaustPmCodec;
    impl FaustPmCodec {
        pub fn new() -> Self {
            FaustPmCodec
        }
    }
    impl AudioCodec for FaustPmCodec {
        fn profile(&self) -> CodecProfile {
            CodecProfile {
                codec_id: CODEC_FAUST_PM,
                sample_rate: PM_RATE,
                channels: 1,
                block_samples: PM_BLOCK as u16,
                max_payload: 8,
            }
        }
        fn encode(&mut self, _pcm: &[f32]) -> Vec<u8> {
            // Host analysis fills PmParams; here we emit a neutral block. Real analysis
            // lives in the demo/SDK and packs via pm_pack().
            pm_pack(&PmParams::default()).to_vec()
        }
        fn decode(&mut self, data: &[u8]) -> Vec<f32> {
            if data.len() != 8 {
                return vec![0.0; PM_BLOCK];
            }
            let mut out = vec![0.0f32; PM_BLOCK];
            unsafe { dcf_pm_synth_block_ffi(data.as_ptr(), out.as_mut_ptr(), PM_BLOCK as i32) };
            out
        }
        fn plc(&mut self) -> Vec<f32> {
            vec![0.0; PM_BLOCK]
        }
    }
}

// SPDX-License-Identifier: LGPL-3.0-only
//! DCF-Game: low-latency multiplayer state/event transport over the DeModFrame wire.
//!
//! Game traffic is an *adapter* over the 17-byte DeModFrame quantum (`frame.rs`), not a
//! new wire format — exactly like DCF-Audio (`audio.rs`). One game message (a state
//! snapshot, an input frame, or an opaque event) is serialised into `1 + frag_total`
//! ordinary DATA frames. This L2 framing is message-type-agnostic and byte-deterministic
//! across C/Rust/Python — it is pinned by `Documentation/game_vectors.json`. See
//! `Documentation/DCF_GAME_SPEC.md`.
//!
//! Layout (all frames version=1, type=DATA(0), big-endian):
//!   seq = packet_id[15:5] (11 bits) | frag_idx[4:0] (5 bits)
//!   frag_idx 0  descriptor : payload = [payload_len, frag_total, msg_type_id, flags]
//!   frag_idx k  data       : payload = bytes[(k-1)*4 .. +4]  (last frame zero-padded)
//!   frag_total = ceil(payload_len/4)  (<= 31  =>  payload_len <= 124 bytes / message)
//!
//! Audio uses CTRL(3); game uses DATA(0), so the two adapters never collide on the wire.

use crate::{Frame, FrameType};
use std::collections::BTreeMap;

// ── L2 constants ────────────────────────────────────────────────────────────
pub const FRAG_BITS: u16 = 5;
pub const FRAG_MASK: u16 = 0x1F;
pub const MAX_FRAGS: usize = 31;
pub const MAX_PAYLOAD: usize = MAX_FRAGS * 4; // 124 bytes / message
pub const MAX_PACKET_ID: u16 = (1 << (16 - FRAG_BITS)) - 1; // 2047

// Message-type registry ids (profiles in DCF_GAME_SPEC.md).
pub const GMSG_SNAPSHOT: u8 = 0; // packed player state (byte-deterministic)
pub const GMSG_INPUT: u8 = 1; // input bitfield + tick (byte-deterministic)
pub const GMSG_EVENT: u8 = 2; // opaque application bytes (not certified)
pub const GMSG_JOIN: u8 = 3; // lobby membership (byte-deterministic)
// ids 4..=255 reserved.

// Descriptor flag bits — request transport behaviour; do not change the L2 bytes.
pub const FLAG_RELIABLE: u8 = 0x01;
pub const FLAG_ORDERED: u8 = 0x02;
pub const FLAG_END_TICK: u8 = 0x04;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum GameError {
    /// Message exceeds the 124-byte cap.
    PayloadTooLarge,
    /// packet_id exceeds the 11-bit field.
    BadPacketId,
}

// ── L2: packetize ───────────────────────────────────────────────────────────
/// Serialise one game message into DeModFrame DATA frames (descriptor first, then
/// data fragments in order). Each frame is a fully valid 17-byte DeModFrame.
pub fn packetize(
    msg_type_id: u8,
    payload: &[u8],
    packet_id: u16,
    ts_us: u32,
    src: u16,
    dst: u16,
    flags: u8,
) -> Result<Vec<[u8; 17]>, GameError> {
    if payload.len() > MAX_PAYLOAD {
        return Err(GameError::PayloadTooLarge);
    }
    if packet_id > MAX_PACKET_ID {
        return Err(GameError::BadPacketId);
    }
    let frag_total = ((payload.len() + 3) / 4) as u8;
    let mut frames = Vec::with_capacity(1 + frag_total as usize);

    // frag_idx 0 — descriptor
    let desc_seq = packet_id << FRAG_BITS;
    let desc = [payload.len() as u8, frag_total, msg_type_id, flags];
    frames.push(Frame::new(1, FrameType::Data, desc_seq, src, dst, desc, ts_us).encode());

    // frag_idx 1..frag_total — data, last chunk zero-padded
    for k in 1..=frag_total {
        let off = (k as usize - 1) * 4;
        let mut chunk = [0u8; 4];
        let end = (off + 4).min(payload.len());
        chunk[..end - off].copy_from_slice(&payload[off..end]);
        let seq = (packet_id << FRAG_BITS) | k as u16;
        frames.push(Frame::new(1, FrameType::Data, seq, src, dst, chunk, ts_us).encode());
    }
    Ok(frames)
}

// ── L2: reassembler ─────────────────────────────────────────────────────────
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct GamePacket {
    pub packet_id: u16,
    pub ts_us: u32,
    pub msg_type_id: u8,
    pub flags: u8,
    pub payload: Vec<u8>,
}

#[derive(Default)]
struct Slot {
    desc: Option<(u8, u8, u8, u8)>, // (payload_len, frag_total, msg_type_id, flags)
    ts_us: u32,
    frags: BTreeMap<u8, [u8; 4]>,
}

/// Stateful reassembler. `push` emits a completed message as soon as its descriptor
/// and every data fragment have arrived; duplicates are ignored; `finalize` reports
/// any still-incomplete message as lost. Mirrors the C and Python references.
#[derive(Default)]
pub struct GameReassembler {
    slots: BTreeMap<u16, Slot>,
}

impl GameReassembler {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&mut self, frame: &[u8; 17]) -> Option<GamePacket> {
        let d = Frame::decode(&frame[..]).ok()?;
        if d.frame_type != FrameType::Data {
            return None;
        }
        let packet_id = d.seq >> FRAG_BITS;
        let frag_idx = (d.seq & FRAG_MASK) as u8;
        let entry = self.slots.entry(packet_id).or_default();
        entry.ts_us = d.timestamp_us;
        if frag_idx == 0 {
            if entry.desc.is_none() {
                entry.desc = Some((d.payload[0], d.payload[1], d.payload[2], d.payload[3]));
            }
        } else {
            entry.frags.entry(frag_idx).or_insert(d.payload);
        }
        self.try_emit(packet_id)
    }

    fn try_emit(&mut self, packet_id: u16) -> Option<GamePacket> {
        let entry = self.slots.get(&packet_id)?;
        let (payload_len, frag_total, msg_type_id, flags) = entry.desc?;
        if (1..=frag_total).any(|k| !entry.frags.contains_key(&k)) {
            return None;
        }
        let mut raw = Vec::with_capacity(frag_total as usize * 4);
        for k in 1..=frag_total {
            raw.extend_from_slice(&entry.frags[&k]);
        }
        raw.truncate(payload_len as usize);
        let ts_us = entry.ts_us;
        self.slots.remove(&packet_id);
        Some(GamePacket { packet_id, ts_us, msg_type_id, flags, payload: raw })
    }

    /// Report every still-incomplete message as lost (ascending packet_id), clearing state.
    pub fn finalize(&mut self) -> Vec<u16> {
        let lost: Vec<u16> = self.slots.keys().copied().collect(); // BTreeMap => sorted
        self.slots.clear();
        lost
    }
}

// ── L1: SNAPSHOT body (msg_type 0) — 14-byte player state, Q8.8 fixed-point ──
pub const SNAPSHOT_LEN: usize = 14;

#[derive(Debug, Clone, Copy, PartialEq, Default)]
pub struct Snapshot {
    pub x: f32,
    pub y: f32,
    pub z: f32,
    pub vx: f32,
    pub vy: f32,
    pub vz: f32,
    pub yaw: u16,
}

fn q88(v: f32) -> [u8; 2] {
    let q = (v * 256.0).round().clamp(-32768.0, 32767.0) as i32 as i16;
    (q as u16).to_be_bytes()
}
fn unq88(b: &[u8]) -> f32 {
    (i16::from_be_bytes([b[0], b[1]]) as f32) / 256.0
}

/// Pack a snapshot into 14 deterministic bytes. The byte layout is certified.
pub fn snapshot_pack(s: &Snapshot) -> [u8; SNAPSHOT_LEN] {
    let mut out = [0u8; SNAPSHOT_LEN];
    for (i, v) in [s.x, s.y, s.z, s.vx, s.vy, s.vz].iter().enumerate() {
        out[i * 2..i * 2 + 2].copy_from_slice(&q88(*v));
    }
    out[12..14].copy_from_slice(&s.yaw.to_be_bytes());
    out
}

/// Unpack 14 bytes into a snapshot. `snapshot_pack(snapshot_unpack(b)) == b`.
pub fn snapshot_unpack(b: &[u8; SNAPSHOT_LEN]) -> Snapshot {
    Snapshot {
        x: unq88(&b[0..2]),
        y: unq88(&b[2..4]),
        z: unq88(&b[4..6]),
        vx: unq88(&b[6..8]),
        vy: unq88(&b[8..10]),
        vz: unq88(&b[10..12]),
        yaw: u16::from_be_bytes([b[12], b[13]]),
    }
}

// ── L1: INPUT body (msg_type 1) — 6 bytes: tick u32 + buttons u16 bitfield ───
pub const INPUT_LEN: usize = 6;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct Input {
    pub tick: u32,
    pub buttons: u16,
}

pub fn input_pack(p: &Input) -> [u8; INPUT_LEN] {
    let mut out = [0u8; INPUT_LEN];
    out[0..4].copy_from_slice(&p.tick.to_be_bytes());
    out[4..6].copy_from_slice(&p.buttons.to_be_bytes());
    out
}
pub fn input_unpack(b: &[u8; INPUT_LEN]) -> Input {
    Input {
        tick: u32::from_be_bytes([b[0], b[1], b[2], b[3]]),
        buttons: u16::from_be_bytes([b[4], b[5]]),
    }
}

// ── L1: JOIN body (msg_type 3) — player_id u16 + len-prefixed UTF-8 name ─────
pub fn join_pack(player_id: u16, name: &str) -> Vec<u8> {
    let nb = name.as_bytes();
    let n = nb.len().min(MAX_PAYLOAD - 3);
    let mut out = Vec::with_capacity(3 + n);
    out.extend_from_slice(&player_id.to_be_bytes());
    out.push(n as u8);
    out.extend_from_slice(&nb[..n]);
    out
}
pub fn join_unpack(b: &[u8]) -> Option<(u16, String)> {
    if b.len() < 3 {
        return None;
    }
    let player_id = u16::from_be_bytes([b[0], b[1]]);
    let n = b[2] as usize;
    let name = String::from_utf8_lossy(&b[3..(3 + n).min(b.len())]).into_owned();
    Some((player_id, name))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn packetize_reassemble_is_identity_under_reorder() {
        let body: Vec<u8> = (0..30u8).collect(); // spans 8 fragments
        let frames = packetize(GMSG_EVENT, &body, 42, 0x010203, 0x00A1, 0xFFFF, FLAG_RELIABLE).unwrap();
        assert_eq!(frames.len(), 1 + (body.len() + 3) / 4);
        // feed in reverse order; reassembly must still recover the exact message
        let mut r = GameReassembler::new();
        let mut got = None;
        for f in frames.iter().rev() {
            if let Some(p) = r.push(f) {
                got = Some(p);
            }
        }
        let p = got.expect("message reassembles regardless of frame order");
        assert_eq!(p.packet_id, 42);
        assert_eq!(p.msg_type_id, GMSG_EVENT);
        assert_eq!(p.flags, FLAG_RELIABLE);
        assert_eq!(p.payload, body);
        assert!(r.finalize().is_empty());
    }

    #[test]
    fn dropped_fragment_is_reported_lost() {
        let body = [1u8, 2, 3, 4, 5, 6, 7];
        let frames = packetize(GMSG_SNAPSHOT, &body, 7, 0, 1, 1, 0).unwrap();
        let mut r = GameReassembler::new();
        for (i, f) in frames.iter().enumerate() {
            if i == 2 {
                continue; // drop one data fragment
            }
            assert!(r.push(f).is_none());
        }
        assert_eq!(r.finalize(), vec![7]); // incomplete => lost
    }

    #[test]
    fn snapshot_input_byte_roundtrip() {
        let s = Snapshot { x: 1.5, y: -2.25, z: 0.0, vx: 0.125, vy: -0.5, vz: 3.0, yaw: 40000 };
        assert_eq!(snapshot_unpack(&snapshot_pack(&s)), s); // Q8.8-representable values
        let i = Input { tick: 0xDEADBEEF, buttons: 0xBEEF };
        assert_eq!(input_unpack(&input_pack(&i)), i);
        let jb = join_pack(0xABCD, "neo");
        assert_eq!(join_unpack(&jb), Some((0xABCD, "neo".to_string())));
    }
}

// SPDX-License-Identifier: LGPL-3.0-only
//! DCF-Text: chat / agent-to-agent text transport over the DeModFrame wire.
//!
//! Text traffic is an *adapter* over the 17-byte DeModFrame quantum (`frame.rs`), not a
//! new wire format — exactly like DCF-Audio (`audio.rs`) and DCF-Game (`game.rs`). One
//! UTF-8 message is fragmented into `1 + frag_total` ordinary DATA frames whose 4-byte
//! payloads carry the bytes. This L2 framing is byte-deterministic across C/Rust/Python —
//! it is pinned by `Documentation/text_vectors.json`. See `Documentation/DCF_TEXT_SPEC.md`.
//!
//! Layout (all frames version=1, type=DATA(0), big-endian):
//!   seq = packet_id[15:10] (6 bits, 0..63) | frag_idx[9:0] (10 bits, 0..1023)
//!   frag_idx 0  descriptor : payload = [len_hi, len_lo, flags, 0]
//!   frag_idx k  data       : payload = bytes[(k-1)*4 .. +4]  (last frame zero-padded)
//!   frag_total = ceil(len/4)  (<= 1023  =>  len <= 4092 bytes / message)
//!
//! Audio uses CTRL(3); text and game ride DATA(0) but use different seq splits (text's
//! 10-bit fragment index vs game's 5-bit), and the descriptor that opens every message
//! tells a receiver which adapter owns the packet_id.

use crate::{crc16_ccitt, Frame, FrameType};
use std::collections::BTreeMap;

// ── L2 constants ────────────────────────────────────────────────────────────
pub const FRAG_BITS: u16 = 10;
pub const FRAG_MASK: u16 = 0x3FF;
pub const MAX_FRAGS: usize = 1023;
pub const MAX_PAYLOAD: usize = MAX_FRAGS * 4; // 4092 bytes / message
pub const MAX_PACKET_ID: u16 = (1 << (16 - FRAG_BITS)) - 1; // 63
pub const BROADCAST: u16 = 0xFFFF;

// Descriptor flag bits — opaque to L2 (they do not change the framing bytes).
pub const FLAG_AGENT: u8 = 0x01;
pub const FLAG_MORE: u8 = 0x02;
pub const FLAG_RELIABLE: u8 = 0x04;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TextError {
    /// Message exceeds the 4092-byte cap.
    PayloadTooLarge,
    /// packet_id exceeds the 6-bit field.
    BadPacketId,
}

/// Map a human channel/passphrase to a 16-bit rendezvous `dst` (the same frequency-channel
/// hash the rest of the repo uses). Empty => broadcast.
pub fn channel_id(name: &str) -> u16 {
    if name.is_empty() {
        BROADCAST
    } else {
        crc16_ccitt(name.as_bytes())
    }
}

// ── L2: packetize ───────────────────────────────────────────────────────────
/// Serialise one UTF-8 message (its raw bytes) into DeModFrame DATA frames (descriptor
/// first, then data fragments in order). Each frame is a fully valid 17-byte DeModFrame.
pub fn packetize(
    payload: &[u8],
    packet_id: u16,
    ts_us: u32,
    src: u16,
    dst: u16,
    flags: u8,
) -> Result<Vec<[u8; 17]>, TextError> {
    if payload.len() > MAX_PAYLOAD {
        return Err(TextError::PayloadTooLarge);
    }
    if packet_id > MAX_PACKET_ID {
        return Err(TextError::BadPacketId);
    }
    let frag_total = ((payload.len() + 3) / 4) as u16;
    let mut frames = Vec::with_capacity(1 + frag_total as usize);

    // frag_idx 0 — descriptor (2-byte big-endian length so the last fragment can be un-padded)
    let desc_seq = packet_id << FRAG_BITS;
    let len = payload.len() as u16;
    let desc = [(len >> 8) as u8, (len & 0xFF) as u8, flags, 0];
    frames.push(Frame::new(1, FrameType::Data, desc_seq, src, dst, desc, ts_us).encode());

    // frag_idx 1..frag_total — data, last chunk zero-padded
    for k in 1..=frag_total {
        let off = (k as usize - 1) * 4;
        let mut chunk = [0u8; 4];
        let end = (off + 4).min(payload.len());
        chunk[..end - off].copy_from_slice(&payload[off..end]);
        let seq = (packet_id << FRAG_BITS) | k;
        frames.push(Frame::new(1, FrameType::Data, seq, src, dst, chunk, ts_us).encode());
    }
    Ok(frames)
}

// ── L2: reassembler ─────────────────────────────────────────────────────────
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TextPacket {
    pub packet_id: u16,
    pub ts_us: u32,
    pub src: u16,
    pub dst: u16,
    pub flags: u8,
    pub text: String,
}

#[derive(Default)]
struct Slot {
    desc: Option<(u16, u8)>, // (payload_len, flags)
    ts_us: u32,
    src: u16,
    dst: u16,
    frags: BTreeMap<u16, [u8; 4]>,
}

/// Stateful reassembler. `push` emits a completed message as soon as its descriptor and
/// every data fragment have arrived; duplicates are ignored; `finalize` reports any
/// still-incomplete message as lost. Mirrors the C and Python references. The reassembler
/// is channel-agnostic — channel filtering, if any, is the caller's job (as in the SDK).
#[derive(Default)]
pub struct TextReassembler {
    slots: BTreeMap<u16, Slot>,
}

impl TextReassembler {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&mut self, frame: &[u8; 17]) -> Option<TextPacket> {
        let d = Frame::decode(&frame[..]).ok()?;
        if d.frame_type != FrameType::Data {
            return None;
        }
        let packet_id = d.seq >> FRAG_BITS;
        let frag_idx = d.seq & FRAG_MASK;
        let entry = self.slots.entry(packet_id).or_default();
        entry.ts_us = d.timestamp_us;
        entry.src = d.src_id;
        entry.dst = d.dst_id;
        if frag_idx == 0 {
            if entry.desc.is_none() {
                let len = ((d.payload[0] as u16) << 8) | d.payload[1] as u16;
                entry.desc = Some((len, d.payload[2]));
            }
        } else {
            entry.frags.entry(frag_idx).or_insert(d.payload);
        }
        self.try_emit(packet_id)
    }

    fn try_emit(&mut self, packet_id: u16) -> Option<TextPacket> {
        let entry = self.slots.get(&packet_id)?;
        let (len, flags) = entry.desc?;
        let frag_total = ((len as usize + 3) / 4) as u16;
        if (1..=frag_total).any(|k| !entry.frags.contains_key(&k)) {
            return None;
        }
        let mut raw = Vec::with_capacity(frag_total as usize * 4);
        for k in 1..=frag_total {
            raw.extend_from_slice(&entry.frags[&k]);
        }
        raw.truncate(len as usize);
        let (ts_us, src, dst) = (entry.ts_us, entry.src, entry.dst);
        self.slots.remove(&packet_id);
        Some(TextPacket {
            packet_id,
            ts_us,
            src,
            dst,
            flags,
            text: String::from_utf8_lossy(&raw).into_owned(),
        })
    }

    /// Report every still-incomplete message as lost (ascending packet_id), clearing state.
    pub fn finalize(&mut self) -> Vec<u16> {
        let lost: Vec<u16> = self.slots.keys().copied().collect(); // BTreeMap => sorted
        self.slots.clear();
        lost
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn packetize_reassemble_is_identity_under_reorder() {
        let msg = "hello over DeModFrame — fragment me"; // spans many fragments
        let frames = packetize(msg.as_bytes(), 5, 0x010203, 0x00A1, 0xFFFF, FLAG_AGENT).unwrap();
        assert_eq!(frames.len(), 1 + (msg.len() + 3) / 4);
        // feed in reverse order; reassembly must still recover the exact message
        let mut r = TextReassembler::new();
        let mut got = None;
        for f in frames.iter().rev() {
            if let Some(p) = r.push(f) {
                got = Some(p);
            }
        }
        let p = got.expect("message reassembles regardless of frame order");
        assert_eq!(p.packet_id, 5);
        assert_eq!(p.src, 0x00A1);
        assert_eq!(p.flags, FLAG_AGENT);
        assert_eq!(p.text, msg);
        assert!(r.finalize().is_empty());
    }

    #[test]
    fn dropped_fragment_is_reported_lost() {
        let frames = packetize(b"dropme over the wire", 9, 0, 1, 2, 0).unwrap();
        let mut r = TextReassembler::new();
        for (i, f) in frames.iter().enumerate() {
            if i == 2 {
                continue; // drop one data fragment
            }
            assert!(r.push(f).is_none());
        }
        assert_eq!(r.finalize(), vec![9]); // incomplete => lost
    }

    #[test]
    fn empty_and_unicode_roundtrip() {
        for msg in ["", "agent ⇄ agent 🚀"] {
            let frames = packetize(msg.as_bytes(), 0, 0, 1, 2, 0).unwrap();
            let mut r = TextReassembler::new();
            let mut got = None;
            for f in &frames {
                if let Some(p) = r.push(f) {
                    got = Some(p);
                }
            }
            assert_eq!(got.unwrap().text, msg);
        }
        assert_eq!(channel_id("123456789"), 0x29B1);
        assert_eq!(channel_id(""), BROADCAST);
    }
}
